{
  "sentences": [
    {
      "text": "你是不是說錯的意思？",
      "pinyin": "Nǐ shì bù shì shuō cuò de yìsi?",
      "pinyin_numeric": "ni3 shi4 bu4 shi4 shuo1 cuo4 de0 yi4 si0",
      "translation_en": "Is it that you said it wrong?",
      "translation_ko": "당신이 잘못 말한 뜻인가요?"
    },
    {
      "text": "他是不是誤會我的意思？",
      "pinyin": "Tā shì bù shì wùhuì wǒ de yìsi?",
      "pinyin_numeric": "ta1 shi4 bu4 shi4 wu4 hui4 wo3 de0 yi4 si0",
      "translation_en": "Is it that he misunderstood me?",
      "translation_ko": "그가 제 뜻을 오해한 건가요?"
    },
    {
      "text": "你是不是以為我生氣的？",
      "pinyin": "Nǐ shì bù shì yǐwéi wǒ shēngqì de?",
      "pinyin_numeric": "ni3 shi4 bu4 shi4 yi3 wei2 wo3 sheng1 qi4 de0",
      "translation_en": "Is it that you thought I was angry?",
      "translation_ko": "당신이 제가 화난 줄 알았던 뜻인가요?"
    },
    {
      "text": "這個句子是不是有錯誤的意思？",
      "pinyin": "Zhège jùzi shì bù shì yǒu cuòwù de yìsi?",
      "pinyin_numeric": "zhe4 ge0 ju4 zi0 shi4 bu4 shi4 you3 cuo4 wu4 de0 yi4 si0",
      "translation_en": "Is it that this sentence has a wrong meaning?",
      "translation_ko": "이 문장이 잘못된 뜻을 가지고 있는 건가요?"
    },
    {
      "text": "你的答案是不是不正確的意思？",
      "pinyin": "Nǐ de dá'àn shì bù shì bù zhèngquè de yìsi?",
      "pinyin_numeric": "ni3 de0 da2 an4 shi4 bu4 shi4 bu4 zheng4 que4 de0 yi4 si0",
      "translation_en": "Is it that your answer is incorrect?",
      "translation_ko": "당신의 답이 정확하지 않은 뜻인가요?"
    },
    {
      "text": "他是不是需要再解釋一次的意思？",
      "pinyin": "Tā shì bù shì xūyào zài jiěshì yīcì de yìsi?",
      "pinyin_numeric": "ta1 shi4 bu4 shi4 xu1 yao4 zai4 jie3 shi4 yi1 ci4 de0 yi4 si0",
      "translation_en": "Is it that he needs to explain again?",
      "translation_ko": "그가 다시 한 번 설명해야 하는 뜻인가요?"
    },
    {
      "text": "你是不是想說「對不起」的意思？",
      "pinyin": "Nǐ shì bù shì xiǎng shuō 'duìbuqǐ' de yìsi?",
      "pinyin_numeric": "ni3 shi4 bu4 shi4 xiang3 shuo1 dui4 bu4 qi3 de0 yi4 si0",
      "translation_en": "Is it that you want to say 'sorry'?",
      "translation_ko": "당신이 '미안합니다'라고 말하고 싶은 뜻인가요?"
    },
    {
      "text": "我是不是說錯話的意思？",
      "pinyin": "Wǒ shì bù shì shuō cuò huà de yìsi?",
      "pinyin_numeric": "wo3 shi4 bu4 shi4 shuo1 cuo4 hua4 de0 yi4 si0",
      "translation_en": "Is it that I said something wrong?",
      "translation_ko": "제가 말을 잘못한 뜻인가요?"
    },
    {
      "text": "你問的問題是不是沒有答案的意思？",
      "pinyin": "Nǐ wèn de wèntí shì bù shì méiyǒu dá'àn de yìsi?",
      "pinyin_numeric": "ni3 wen4 de0 wen4 ti2 shi4 bu4 shi4 mei2 you3 da2 an4 de0 yi4 si0",
      "translation_en": "Is it that the question you asked has no answer?",
      "translation_ko": "당신이 물은 질문에 답이 없는 뜻인가요?"
    },
    {
      "text": "他是不是以為我生氣的，其實我沒有？",
      "pinyin": "Tā shì bù shì yǐwéi wǒ shēngqì de, qíshí wǒ méiyǒu?",
      "pinyin_numeric": "ta1 shi4 bu4 shi4 yi3 wei2 wo3 sheng1 qi4 de0, qi2 shi2 wo3 mei2 you3",
      "translation_en": "Is it that he thought I was angry, but actually I wasn't?",
      "translation_ko": "그가 제가 화난 줄 알았는데, 사실은 안 그랬던 뜻인가요?"
    }
  ]
}
